public static void main(Args args)
{
    var builder = DBMSQLDBTuningRecommendationsViewBuilder::construct();
    builder.createSqlObjects();
}

private str createViewSqlStmt()
{
    str sqlStmt = 'CREATE VIEW ' + viewName + ' AS ' + this.createSQLStatement();
    return sqlStmt;
}

private str createSQLStatement()
{
    if (DBMSQLUtils::databaseCompatibilityLevel() >= 140)
    {
        return this.createSQLStatement140();
    }
    else
    {
        return this.createSQLStatementFallback();
    }
}

protected void initialize(boolean _runOnSeparateUserConnection = false)
{
    super(_runOnSeparateUserConnection);

    SysDictView view    = new SysDictView(tableNum(DBMSQLDBTuningRecommendations));
    viewName            = view.name(DbBackend::Sql);
    asName = view.fieldObject(fieldNum(DBMSQLDBTuningRecommendations, Name)).name(DbBackend::Sql);
    asType = view.fieldObject(fieldNum(DBMSQLDBTuningRecommendations, Type)).name(DbBackend::Sql);
    asReason = view.fieldObject(fieldNum(DBMSQLDBTuningRecommendations, Reason)).name(DbBackend::Sql);
    asValidSince = view.fieldObject(fieldNum(DBMSQLDBTuningRecommendations, ValidSince)).name(DbBackend::Sql);
    asLastRefresh = view.fieldObject(fieldNum(DBMSQLDBTuningRecommendations, LastRefresh)).name(DbBackend::Sql);
    asState = view.fieldObject(fieldNum(DBMSQLDBTuningRecommendations, State)).name(DbBackend::Sql);
    asIsExecutableAction = view.fieldObject(fieldNum(DBMSQLDBTuningRecommendations, IsExecutableAction)).name(DbBackend::Sql);
    asIsRevertableAction = view.fieldObject(fieldNum(DBMSQLDBTuningRecommendations, IsRevertableAction)).name(DbBackend::Sql);
    asExecuteActionStartTime = view.fieldObject(fieldNum(DBMSQLDBTuningRecommendations, ExecuteActionStartTime)).name(DbBackend::Sql);
    asExecuteActionDuration = view.fieldObject(fieldNum(DBMSQLDBTuningRecommendations, ExecuteActionDuration)).name(DbBackend::Sql);
    asExecuteActionInitiatedBy = view.fieldObject(fieldNum(DBMSQLDBTuningRecommendations, ExecuteActionInitiatedBy)).name(DbBackend::Sql);
    asExecuteActionInitiatedTime = view.fieldObject(fieldNum(DBMSQLDBTuningRecommendations, ExecuteActionInitiatedTime)).name(DbBackend::Sql);
    asRevertActionStartTime = view.fieldObject(fieldNum(DBMSQLDBTuningRecommendations, RevertActionStartTime)).name(DbBackend::Sql);
    asRevertActionDuration = view.fieldObject(fieldNum(DBMSQLDBTuningRecommendations, RevertActionDuration)).name(DbBackend::Sql);
    asRevertActionInitiatedBy = view.fieldObject(fieldNum(DBMSQLDBTuningRecommendations, RevertActionInitiatedBy)).name(DbBackend::Sql);
    asRevertActionInitiatedTime = view.fieldObject(fieldNum(DBMSQLDBTuningRecommendations, RevertActionInitiatedTime)).name(DbBackend::Sql);
    asScore = view.fieldObject(fieldNum(DBMSQLDBTuningRecommendations, Score)).name(DbBackend::Sql);
    asDetails = view.fieldObject(fieldNum(DBMSQLDBTuningRecommendations, Details)).name(DbBackend::Sql);
    asRecId = view.fieldObject(fieldNum(DBMSQLDBTuningRecommendations, RecId)).name(DbBackend::Sql);
}

public static DBMSQLDBTuningRecommendationsViewBuilder construct()
{
    return new DBMSQLDBTuningRecommendationsViewBuilder();
}
